#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *freq = calloc(N+1, sizeof(int));
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x<=N) freq[x]++;
        }
        int maxFreq=0, cntMax=0;
        for(int i=1;i<=N;i++){
            if(freq[i]>maxFreq){
                maxFreq=freq[i]; cntMax=1;
            } else if(freq[i]==maxFreq && maxFreq>0){
                cntMax++;
            }
        }
        printf(cntMax==1?"YES\n":"NO\n");
        free(freq);
    }
    return 0;
}

