#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        freq = [0] * (N + 1)
        for _ in range(N):
            x = int(next(it))
            if x <= N:
                freq[x] += 1
        maxFreq = max(freq)
        if maxFreq == 0:
            out_lines.append("NO")
            continue
        cntMax = freq.count(maxFreq)
        out_lines.append("YES" if cntMax == 1 else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

